mapper.select:
SELECT hs.id, hs.homework_id, h.homework_title, h.course_id, hs.student_id, hs.submission_content, hs.attachment_url, hs.submission_time, hs.score, hs.feedback, hs.graded_by, hs.graded_time, hs.status, h.total_score AS homework_total_score, hs.created_time FROM homework_submission hs INNER JOIN homework h ON h.id = hs.homework_id
AND hs.student_id = #{q.studentId}
AND hs.homework_id = #{q.homeworkId}
AND hs.status = #{q.status}
AND EXISTS ( SELECT 1 FROM homework h WHERE h.id = hs.homework_id AND h.course_id = #{q.courseId} )
ORDER BY hs.submission_time DESC

SELECT hs.id, hs.homework_id, h.homework_title, h.course_id, hs.student_id, hs.submission_content, hs.attachment_url, hs.submission_time, hs.score, hs.feedback, hs.graded_by, hs.graded_time, hs.status, h.total_score AS homework_total_score, hs.created_time FROM homework_submission hs INNER JOIN homework h ON h.id = hs.homework_id
AND h.teacher_id = #{q.teacherId}
AND hs.homework_id = #{q.homeworkId}
AND h.course_id = #{q.courseId}
AND hs.status = #{q.status}
ORDER BY
hs.graded_time
hs.score
hs.submission_time
ASC
DESC
